using System;
using System.Drawing;
using System.Linq;
using System.Windows.Forms;

namespace NoiseTest
{
    /// <summary>
    /// IO 모니터 폼 — IN/OUT 각 32채널
    /// 레이아웃: IN00-15 | IN16-31 | OUT00-15 | OUT16-31 (16행 × 4열)
    /// 폼: 820 × 681
    /// </summary>
    public partial class FrmIO : Form
    {
        private const int CH   = 32;
        private const int ROWS = 16;

        private PictureBox[] _inPics  = new PictureBox[CH];
        private PictureBox[] _outPics = new PictureBox[CH];
        private Label[]      _inLbls  = new Label[CH];
        private Label[]      _outLbls = new Label[CH];

        private bool _updating = false;

        public FrmIO()
        {
            InitializeComponent();
            CreateIoControls();
            SetupIOLabels();

            timer1.Interval = 100;
            timer1.Tick += timer1_Tick;
            timer1.Start();
        }

        // ===== 동적 컨트롤 생성 =====

        private void CreateIoControls()
        {
            const int PB_W    = 58;
            const int PB_H    = 54;   // 2배
            const int LBL_H   = 44;   // 2배
            const int Y_START = 22;   // 헤더 아래
            const int Y_STEP  = 72;   // 행 간격 2배 (16행 × 72 = 1152)

            // 열 좌표 (폼 너비 1100px, 컬럼 너비 200px)
            const int C1_PB  =   6;  const int C1_LBL =  70; const int C1_W = 200;  // IN00-15
            const int C2_PB  = 278;  const int C2_LBL = 342; const int C2_W = 200;  // IN16-31
            const int C3_PB  = 554;  const int C3_LBL = 618; const int C3_W = 200;  // OUT00-15
            const int C4_PB  = 826;  const int C4_LBL = 890; const int C4_W = 200;  // OUT16-31

            for (int row = 0; row < ROWS; row++)
            {
                int y   = Y_START + row * Y_STEP;
                int in0 = row;       // IN00-15
                int in1 = row + 16;  // IN16-31
                int ou0 = row;       // OUT00-15
                int ou1 = row + 16;  // OUT16-31

                CreateIn (in0, y, C1_PB, C1_LBL, C1_W, PB_W, PB_H, LBL_H);
                CreateIn (in1, y, C2_PB, C2_LBL, C2_W, PB_W, PB_H, LBL_H);
                CreateOut(ou0, y, C3_PB, C3_LBL, C3_W, PB_W, PB_H, LBL_H);
                CreateOut(ou1, y, C4_PB, C4_LBL, C4_W, PB_W, PB_H, LBL_H);
            }

            // IN/OUT 구분선 (C2 끝 ~ C3 사이)
            panel3.Controls.Add(new Label
            {
                Location  = new Point(544, 0),
                Size      = new Size(4, panel3.Height),
                BackColor = Color.DimGray,
                Text      = ""
            });

            // 컬럼 헤더
            AddHeader("INPUT  (IN00~IN31)",   6,   3, 534);
            AddHeader("OUTPUT (OUT00~OUT31)", 552,  3, 540);
        }

        private void CreateIn(int i, int y, int pbX, int lblX, int lblW,
                               int pbW, int pbH, int lblH)
        {
            var pic = new PictureBox
            {
                Size = new Size(pbW, pbH), Location = new Point(pbX, y),
                BackColor = Color.Black,   Name = $"picIn{i}"
            };
            MakeCircle(pic);
            AddOverlayLabel(pic, $"IN{i:D2}");
            panel3.Controls.Add(pic);
            _inPics[i] = pic;

            var lbl = new Label
            {
                Size = new Size(lblW, lblH), Location = new Point(lblX, y + 4),
                Text = $"IN{i:D2}", TextAlign = ContentAlignment.MiddleLeft,
                Font = new Font("Segoe UI", 8), Name = $"lblIn{i}"
            };
            panel3.Controls.Add(lbl);
            _inLbls[i] = lbl;
        }

        private void CreateOut(int i, int y, int pbX, int lblX, int lblW,
                                int pbW, int pbH, int lblH)
        {
            var pic = new PictureBox
            {
                Size = new Size(pbW, pbH), Location = new Point(pbX, y),
                BackColor = Color.Black,   Name = $"picOut{i}", Tag = i
            };
            MakeCircle(pic);
            AddOverlayLabel(pic, $"OUT{i:D2}");
            pic.Click += pictureBoxOutput_Click;
            var ol = GetOverlayLabel(pic);
            if (ol != null) { var cap = pic; ol.Click += (s, e) => pictureBoxOutput_Click(cap, EventArgs.Empty); }
            panel3.Controls.Add(pic);
            _outPics[i] = pic;

            var lbl = new Label
            {
                Size = new Size(lblW, lblH), Location = new Point(lblX, y + 4),
                Text = $"OUT{i:D2}", TextAlign = ContentAlignment.MiddleLeft,
                Font = new Font("Segoe UI", 8), Name = $"lblOut{i}"
            };
            panel3.Controls.Add(lbl);
            _outLbls[i] = lbl;
        }

        private void AddHeader(string text, int x, int y, int width)
        {
            panel3.Controls.Add(new Label
            {
                Location = new Point(x, y), Size = new Size(width, 16),
                Text = text, Font = new Font("Segoe UI", 8, FontStyle.Bold),
                ForeColor = Color.DimGray, TextAlign = ContentAlignment.MiddleLeft
            });
        }

        // ===== IO 역할명 =====

        private void SetupIOLabels()
        {
            string[] inputNames = new string[]
            {
                "시작 버튼",        // IN00
                "리셋 스위치",      // IN01
                "비상정지(B접)",    // IN02
                "클램프 센서",      // IN03
                "언클램프 센서",    // IN04
                "검사위치 센서",    // IN05
                "원위치 센서",      // IN06
                "웨이트 하강 센서", // IN07
                "웨이트 상승 센서", // IN08
                "전진센서",         // IN09
                "하강",             // IN10
                "상승",             // IN11
                "-",                // IN12
                "게이지 전진 센서", // IN13
                "게이지 후진 센서", // IN14
                "웨이트고정 후진1", // IN15
                "웨이트고정 전진1", // IN16
                "웨이트고정 전진2", // IN17
                "웨이트고정 후진2", // IN18
                "-",                // IN19
                "-",                // IN20
                "-",                // IN21
                "통전 검출",        // IN22
                "각도기 감지1",     // IN23
                "각도기 감지2",     // IN24
                "-",                // IN25
                "-",                // IN26
                "-",                // IN27
                "-",                // IN28
                "-",                // IN29
                "-",                // IN30
                "-"                 // IN31
            };

            string[] outputNames = new string[]
            {
                "클램프",           // OUT00
                "언클램프",         // OUT01
                "검사위치 이동",    // OUT02
                "원위치 이동",      // OUT03
                "웨이트 하강",      // OUT04
                "웨이트 상승",      // OUT05
                "-",                // OUT06
                "-",                // OUT07
                "-",                // OUT08
                "-",                // OUT09
                "게이지 전진",      // OUT10
                "게이지 후진",      // OUT11
                "웨이트고정 전진1", // OUT12
                "웨이트고정 후진1", // OUT13
                "웨이트고정 전진2", // OUT14
                "웨이트고정 후진2", // OUT15
                "-",                // OUT16
                "-",                // OUT17
                "-",                // OUT18
                "-",                // OUT19
                "-",                // OUT20
                "-",                // OUT21
                "-",                // OUT22
                "-",                // OUT23
                "CW 동작",          // OUT24
                "CCW 동작",         // OUT25
                "원형고정",         // OUT26
                "원형해제",         // OUT27
                "상승",             // OUT28
                "하강",             // OUT29
                "전진",             // OUT30
                "후진"              // OUT31
            };

            for (int i = 0; i < CH; i++)
            {
                if (_inLbls[i]  != null) _inLbls[i].Text  = $"IN{i:D2}  {inputNames[i]}";
                if (_outLbls[i] != null) _outLbls[i].Text = $"OUT{i:D2} {outputNames[i]}";
            }
        }

        // ===== UI 헬퍼 =====

        private void MakeCircle(PictureBox pic)
        {
            var gp = new System.Drawing.Drawing2D.GraphicsPath();
            gp.AddEllipse(0, 0, pic.Width - 1, pic.Height - 1);
            pic.Region = new Region(gp);
        }

        private void AddOverlayLabel(PictureBox pic, string text)
        {
            var old = GetOverlayLabel(pic);
            if (old != null) pic.Controls.Remove(old);
            pic.Controls.Add(new Label
            {
                Text = text, AutoSize = false,
                TextAlign = ContentAlignment.MiddleCenter, Dock = DockStyle.Fill,
                BackColor = Color.White, ForeColor = Color.Black,
                Font = new Font("Segoe UI", 7, FontStyle.Bold), Name = "OverlayLabel"
            });
        }

        private static Label GetOverlayLabel(PictureBox pic)
            => pic?.Controls.OfType<Label>().FirstOrDefault(l => l.Name == "OverlayLabel");

        private void ApplyOnOffStyle(PictureBox pic, bool isOn)
        {
            if (pic == null) return;
            pic.BackColor = isOn ? Color.Blue : Color.Black;
            var lbl = GetOverlayLabel(pic);
            if (lbl != null)
            {
                lbl.BackColor = isOn ? Color.Black : Color.White;
                lbl.ForeColor = isOn ? Color.White : Color.Black;
            }
        }

        // ===== 출력 토글 클릭 =====

        private void pictureBoxOutput_Click(object sender, EventArgs e)
        {
            var pic = sender as PictureBox;
            if (pic == null || FrmMain.io == null) return;

            int index = -1;
            if (pic.Tag is int i) index = i;
            else if (!int.TryParse(pic.Tag + "", out index)) return;
            if (index < 0 || index >= CH) return;

            bool next = !FrmMain.io.GetOutput(index);
            if (next) { FrmMain.io.Do_On_Force(index);  FrmMain.io.Commit(); }
            else      { FrmMain.io.Do_Off_Force(index); FrmMain.io.Commit(); }

            ApplyOnOffStyle(pic, next);
        }

        // ===== 주기 갱신 =====

        private void timer1_Tick(object sender, EventArgs e)
        {
            if (_updating) return;
            _updating = true;
            try
            {
                var io = FrmMain.io;
                if (io == null) return;
                for (int i = 0; i < CH; i++)
                {
                    ApplyOnOffStyle(_inPics[i],  io.GetInput(i));
                    ApplyOnOffStyle(_outPics[i], io.GetOutput(i));
                }
            }
            catch { }
            finally { _updating = false; }
        }

        // ===== 버튼 핸들러 =====

        private void btnClose_Click(object sender, EventArgs e) => this.Close();
        private void button1_Click(object sender, EventArgs e) => ToggleButton(button1, 24);
        private void button2_Click(object sender, EventArgs e) => ToggleButton(button2, 25);
        private void button3_Click(object sender, EventArgs e) => ToggleButton(button3, 26);
        private void button4_Click(object sender, EventArgs e) => ToggleButton(button4, 27);

        private void ToggleButton(Button btn, int outIndex)
        {
            if (FrmMain.io == null) return;
            if (btn.BackColor == Color.White)
            { FrmMain.io.Do_On_Force(outIndex);  FrmMain.io.Commit(); btn.BackColor = Color.Black; btn.ForeColor = Color.White; }
            else
            { FrmMain.io.Do_Off_Force(outIndex); FrmMain.io.Commit(); btn.BackColor = Color.White; btn.ForeColor = Color.Black; }
        }
    }
}
